// pandasDtypeToStr converts a pandas dtype name to a SQL type string.
func pandasDtypeToStr(dtype string) string {
	if strings.HasPrefix(dtype, "int") || strings.HasPrefix(dtype, "Int") {
		return "INTEGER"
	}
	if strings.HasPrefix(dtype, "float") || strings.HasPrefix(dtype, "Float") {
		return "FLOAT"
	}
	if strings.HasPrefix(dtype, "bool") {
		return "BOOLEAN"
	}
	if strings.HasPrefix(dtype, "datetime") {
		return "TIMESTAMP"
	}
	return "TEXT"
}

