import (
	"encoding/json"
	"fmt"
)

// inferJSON parses JSON bytes and returns a TableMeta describing its schema.
func inferJSON(data []byte, name string) (*TableMeta, error) {
	var raw interface{}
	if err := json.Unmarshal(data, &raw); err != nil {
		return nil, fmt.Errorf("cannot parse JSON for %q: %w", name, err)
	}

	switch obj := raw.(type) {
	case []interface{}:
		keyTypes := map[string]string{}
		limit := len(obj)
		if limit > 100 {
			limit = 100
		}
		for _, rawItem := range obj[:limit] {
			item, ok := rawItem.(map[string]interface{})
			if !ok {
				continue
			}
			for k, v := range item {
				if _, exists := keyTypes[k]; !exists {
					keyTypes[k] = pythonTypeToStr(v)
				}
			}
		}
		columns := make([]ColumnMeta, 0, len(keyTypes))
		for k, v := range keyTypes {
			columns = append(columns, ColumnMeta{Name: k, DataType: v})
		}
		return &TableMeta{Name: name, Columns: columns, RowCount: len(obj)}, nil

	case map[string]interface{}:
		columns := make([]ColumnMeta, 0, len(obj))
		count := 0
		for k, v := range obj {
			if count >= 100 {
				break
			}
			columns = append(columns, ColumnMeta{Name: k, DataType: pythonTypeToStr(v)})
			count++
		}
		return &TableMeta{Name: name, Columns: columns, RowCount: 1}, nil
	}

	return &TableMeta{Name: name}, nil
}

