import (
	"bufio"
	"bytes"
	"encoding/json"
	"fmt"
)

// inferJSONL streams JSONL bytes, infers column types from up to 100 objects,
// and returns a TableMeta with the total line count.
func inferJSONL(data []byte, name string) (*TableMeta, error) {
	keyTypes := map[string]string{}
	count := 0
	total := 0
	parseFailures := 0

	scanner := bufio.NewScanner(bytes.NewReader(data))
	for scanner.Scan() {
		line := bytes.TrimSpace(scanner.Bytes())
		if len(line) == 0 {
			continue
		}
		total++
		if count < 100 {
			var obj map[string]interface{}
			if err := json.Unmarshal(line, &obj); err != nil {
				parseFailures++
			} else {
				for k, v := range obj {
					if _, exists := keyTypes[k]; !exists {
						keyTypes[k] = pythonTypeToStr(v)
					}
				}
				count++
			}
		}
	}

	if total > 0 && count == 0 {
		return nil, fmt.Errorf("all %d non-empty lines in %q failed JSON parsing", parseFailures, name)
	}

	columns := make([]ColumnMeta, 0, len(keyTypes))
	for k, v := range keyTypes {
		columns = append(columns, ColumnMeta{Name: k, DataType: v})
	}
	return &TableMeta{Name: name, Columns: columns, RowCount: total}, nil
}

import (
	"fmt"

	"github.com/apache/arrow/go/v17/arrow/ipc"
	"github.com/apache/arrow/go/v17/parquet/file"
	"github.com/apache/arrow/go/v17/parquet/pqarrow"
)

// inferParquet reads a Parquet, Arrow IPC stream, or Feather file from bytes
// and returns a TableMeta with field names, inferred SQL types, and row count.
func inferParquet(data []byte, ext string, name string) (*TableMeta, error) {
	var columns []ColumnMeta
	var rowCount *int64

	switch ext {
	case ".arrow":
		reader, err := ipc.NewReader(bytes.NewReader(data))
		if err != nil {
			return nil, fmt.Errorf("open arrow ipc stream: %w", err)
		}
		defer reader.Release()
		schema := reader.Schema()
		for i := 0; i < schema.NumFields(); i++ {
			f := schema.Field(i)
			columns = append(columns, ColumnMeta{Name: f.Name, DataType: arrowTypeToStr(f.Type)})
		}
		// row count not available from schema alone

	case ".feather":
		reader, err := ipc.NewFileReader(bytes.NewReader(data))
		if err != nil {
			return nil, fmt.Errorf("open feather file: %w", err)
		}
		defer reader.Release()
		schema := reader.Schema()
		for i := 0; i < schema.NumFields(); i++ {
			f := schema.Field(i)
			columns = append(columns, ColumnMeta{Name: f.Name, DataType: arrowTypeToStr(f.Type)})
		}
		n := int64(reader.NumRecords())
		rowCount = &n

	default: // .parquet
		pf, err := file.OpenParquetFile("", false, file.WithReader(bytes.NewReader(data)))
		if err != nil {
			return nil, fmt.Errorf("open parquet file: %w", err)
		}
		defer pf.Close()
		arrowSchema, err := pqarrow.FromParquet(pf.MetaData().Schema, nil, nil)
		if err != nil {
			return nil, fmt.Errorf("read parquet arrow schema: %w", err)
		}
		for i := 0; i < arrowSchema.NumFields(); i++ {
			f := arrowSchema.Field(i)
			columns = append(columns, ColumnMeta{Name: f.Name, DataType: arrowTypeToStr(f.Type)})
		}
		n := pf.MetaData().NumRows
		rowCount = &n
	}

	return &TableMeta{Name: name, Columns: columns, RowCount: rowCount}, nil
}

