import (
	"fmt"
	"sync"
)

// VersionedRef is a thread-safe generic versioned holder.
// version is -1 when no initial value was provided, 0+ after the first set.
type VersionedRef[T any] struct {
	mu      sync.Mutex
	current *T
	pending *T
	version int
}

// NewVersionedRef creates a VersionedRef. Pass nil for initial to start unset (version -1).
func NewVersionedRef[T any](initial *T) *VersionedRef[T] {
	v := &VersionedRef[T]{}
	if initial != nil {
		v.current = initial
		v.version = 0
	} else {
		v.version = -1
	}
	return v
}

// Current returns the active value. Thread-safe.
func (r *VersionedRef[T]) Current() *T {
	r.mu.Lock()
	defer r.mu.Unlock()
	return r.current
}

// Version returns the monotonically increasing version counter. -1 means never set.
func (r *VersionedRef[T]) Version() int {
	r.mu.Lock()
	defer r.mu.Unlock()
	return r.version
}

// HasPending returns true if a staged value is waiting to be promoted.
func (r *VersionedRef[T]) HasPending() bool {
	r.mu.Lock()
	defer r.mu.Unlock()
	return r.pending != nil
}

// Update atomically replaces the current value and returns the new version number.
func (r *VersionedRef[T]) Update(value T) int {
	r.mu.Lock()
	defer r.mu.Unlock()
	r.current = &value
	r.pending = nil
	r.version++
	return r.version
}

// Stage stores a pending value without activating it.
func (r *VersionedRef[T]) Stage(value T) {
	r.mu.Lock()
	defer r.mu.Unlock()
	r.pending = &value
}

// Promote activates the staged value as current and returns the new version number.
func (r *VersionedRef[T]) Promote() (int, error) {
	r.mu.Lock()
	defer r.mu.Unlock()
	if r.pending == nil {
		return 0, fmt.Errorf("Promote called with nothing staged")
	}
	r.current = r.pending
	r.pending = nil
	r.version++
	return r.version, nil
}

// DiscardStaged discards the staged value without promoting it.
func (r *VersionedRef[T]) DiscardStaged() {
	r.mu.Lock()
	defer r.mu.Unlock()
	r.pending = nil
}

