// checkAll fetches all namespace IDs from the global DB and triggers async
// rebuilds for any namespace whose cache is stale and has no running build.
func (r *NamespaceRefresher) checkAll() {
	globalDBPath, err := r.dbPathFn("global")
	if err != nil {
		return
	}

	namespaceIDs, err := fetchNamespaceIDs(globalDBPath)
	if err != nil {
		return
	}

	for _, nsID := range namespaceIDs {
		r.mu.Lock()
		handle, exists := r.active[nsID]
		r.mu.Unlock()
		if exists && handle != nil && handle.Running() {
			continue
		}

		dbPath, err := r.dbPathFn(nsID)
		if err != nil {
			continue
		}
		store, err := OpenStore(dbPath, true)
		if err != nil {
			continue
		}
		valid := store.NamespaceCacheValid(nsID)
		store.Close()

		if !valid {
			r.onRebuild(nsID)
			nextPath, _ := r.dbPathFn(nsID)
			newHandle := buildNamespaceAsync(nsID, nextPath, r.embedModel, r.buildOpts)
			r.mu.Lock()
			r.active[nsID] = newHandle
			r.mu.Unlock()
		}
	}
}

// sourceRow holds one row from the sources JOIN domains query.
type sourceRow struct {
	SourceID  string
	SType     string
	URI       string
	ConfigJSON string
	DomainID  string
}

// indexSources iterates over source rows, builds per-source config maps,
// calls indexer.IndexSource for each, stamps last_crawled, then marks the
// namespace built and reports embed progress.
func indexSources(
	sources []sourceRow,
	namespaceID string,
	indexer *Indexer,
	store *Store,
	onProgress func(string, int, int),
) error {
	totalChunks := 0
	for _, src := range sources {
		config := map[string]interface{}{}
		if len(src.ConfigJSON) > 0 {
			if err := json.Unmarshal([]byte(src.ConfigJSON), &config); err != nil {
				return fmt.Errorf("parse config for source %s: %w", src.SourceID, err)
			}
		}
		config["source_id"] = src.SourceID
		config["type"] = src.SType
		config["uri"] = src.URI
		config["domain_id"] = src.DomainID
		config["namespace"] = namespaceID

		n, err := indexer.IndexSource(config)
		if err != nil {
			return fmt.Errorf("index source %s: %w", src.SourceID, err)
		}
		totalChunks += n

		if err := store.Exec(
			"UPDATE sources SET last_crawled = now() WHERE source_id = ?",
			src.SourceID,
		); err != nil {
			return fmt.Errorf("stamp last_crawled for %s: %w", src.SourceID, err)
		}
	}

	if err := store.MarkNamespaceBuilt(namespaceID, "chunks"); err != nil {
		return fmt.Errorf("mark namespace built: %w", err)
	}
	onProgress("embed", totalChunks, totalChunks)
	return nil
}

// runNERAndCommunityPhases executes the NER and community build phases when
// their respective flags are set, invoking onError and returning on failure.
func runNERAndCommunityPhases(
	store *Store,
	dbPath string,
	embedModel interface{},
	namespaceID string,
	spacyModel string,
	communityAlpha float64,
	communitySimThreshold float64,
	force bool,
	runNER bool,
	runCommunity bool,
	onProgress func(string, int, int),
	onError func(string, error),
) error {
	if runNER {
		onProgress("ner", 0, 1)
		if err := BuildNER(store, spacyModel, namespaceID); err != nil {
			onError("ner", err)
			return err
		}
		if err := store.MarkNamespaceBuilt(namespaceID, "ner"); err != nil {
			onError("ner", err)
			return err
		}
		onProgress("ner", 1, 1)
	}

	if runCommunity {
		onProgress("community", 0, 1)
		if err := BuildCommunity(dbPath, embedModel, namespaceID, communityAlpha, communitySimThreshold, force); err != nil {
			onError("community", err)
			return err
		}
		if err := store.MarkNamespaceBuilt(namespaceID, "community"); err != nil {
			onError("community", err)
			return err
		}
		onProgress("community", 1, 1)
	}

	return nil
}

import "sync"

// BuildOpts holds optional parameters for BuildNamespaceAsync.
type BuildOpts struct {
	OnProgress           func(phase string, done, total int)
	OnComplete           func(totalChunks int)
	OnError              func(phase string, err error)
	Force                bool
	RunNER               bool
	RunCommunity         bool
	SpacyModel           string
	CommunityAlpha       float64
	CommunitySimThreshold float64
	EmbedBatchSize       int
}

// BuildNamespaceAsync launches the full index pipeline for namespaceID in a
// background goroutine and returns an IndexHandle for the caller to join.
func BuildNamespaceAsync(namespaceID string, dbPath string, embedModel interface{}, opts BuildOpts) *IndexHandle {
	onProgress := opts.OnProgress
	if onProgress == nil {
		onProgress = func(string, int, int) {}
	}
	onComplete := opts.OnComplete
	if onComplete == nil {
		onComplete = func(int) {}
	}
	onError := opts.OnError
	if onError == nil {
		onError = func(string, error) {}
	}
	if opts.SpacyModel == "" {
		opts.SpacyModel = "en_core_web_sm"
	}
	if opts.CommunityAlpha == 0 {
		opts.CommunityAlpha = 0.2
	}
	if opts.CommunitySimThreshold == 0 {
		opts.CommunitySimThreshold = 0.6
	}
	if opts.EmbedBatchSize == 0 {
		opts.EmbedBatchSize = 256
	}

	var wg sync.WaitGroup
	wg.Add(1)
	go func() {
		defer wg.Done()
		runPipeline(namespaceID, dbPath, embedModel, opts, onProgress, onComplete, onError)
	}()
	return NewIndexHandle(&wg)
}

import (
	"sync"
	"time"
)

// NamespaceRefresher periodically checks all registered namespaces and
// triggers async rebuilds for any whose cache is stale.
type NamespaceRefresher struct {
	dbPathFn   func(namespaceID string) (string, error)
	embedModel interface{}
	interval   time.Duration
	onRebuild  func(namespaceID string)
	buildOpts  BuildOpts
	stopCh     chan struct{}
	loopDone   sync.WaitGroup
	mu         sync.Mutex
	active     map[string]*IndexHandle
}

// NewNamespaceRefresher constructs a NamespaceRefresher.
// intervalSeconds defaults to 3600 when zero.
func NewNamespaceRefresher(
	dbPathFn func(string) (string, error),
	embedModel interface{},
	intervalSeconds int,
	onRebuild func(string),
	buildOpts BuildOpts,
) *NamespaceRefresher {
	if intervalSeconds == 0 {
		intervalSeconds = 3600
	}
	if onRebuild == nil {
		onRebuild = func(string) {}
	}
	return &NamespaceRefresher{
		dbPathFn:   dbPathFn,
		embedModel: embedModel,
		interval:   time.Duration(intervalSeconds) * time.Second,
		onRebuild:  onRebuild,
		buildOpts:  buildOpts,
		stopCh:     make(chan struct{}),
		active:     map[string]*IndexHandle{},
	}
}

// Start launches the background refresh loop (non-blocking).
func (r *NamespaceRefresher) Start() {
	r.stopCh = make(chan struct{})
	r.loopDone.Add(1)
	go func() {
		defer r.loopDone.Done()
		r.loop()
	}()
}
